solutions.javascript:
// Solution
function insert(word, trie) {
  if (!trie) trie = {};
  if (word.length === 0) return trie;
  let char = word[0];
  if (trie[char]) return trie[char];
  trie[char] = {};
  return insert(word.slice(1), trie[char]);
}
